using Microsoft.VisualStudio.TestTools.UnitTesting;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class PaginatedListTests
    {
        [TestMethod]
        public void Constructor_SetsPageIndexAndTotalPages()
        {
            var items = new List<string> { "a", "b" };

            var list = new PaginatedList<string>(items, 10, 2, 3);

            Assert.AreEqual(2, list.PageIndex);
            Assert.AreEqual(4, list.TotalPages); // ceil(10/3) = 4
            Assert.AreEqual(2, list.Count);
        }

        [TestMethod]
        public void HasPreviousPage_PageOne_ReturnsFalse()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);
            Assert.IsFalse(list.HasPreviousPage);
        }

        [TestMethod]
        public void HasPreviousPage_PageTwo_ReturnsTrue()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);
            Assert.IsTrue(list.HasPreviousPage);
        }

        [TestMethod]
        public void HasNextPage_LastPage_ReturnsFalse()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 2, 5); // TotalPages = 2
            Assert.IsFalse(list.HasNextPage);
        }

        [TestMethod]
        public void HasNextPage_NotLastPage_ReturnsTrue()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 1, 5); // TotalPages = 2
            Assert.IsTrue(list.HasNextPage);
        }

        [TestMethod]
        public void Create_ReturnsCorrectPage()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var page = PaginatedList<int>.Create(source, 2, 10);

            Assert.AreEqual(2, page.PageIndex);
            Assert.AreEqual(3, page.TotalPages); // ceil(25/10) = 3
            Assert.AreEqual(10, page.Count);
            Assert.AreEqual(11, page[0]); // second page starts at 11
            Assert.AreEqual(20, page[9]);
        }

        [TestMethod]
        public void Create_FirstPage_ContainsFirstItems()
        {
            var source = Enumerable.Range(1, 5).AsQueryable();

            var page = PaginatedList<int>.Create(source, 1, 3);

            Assert.AreEqual(3, page.Count);
            Assert.AreEqual(1, page[0]);
            Assert.AreEqual(3, page[2]);
            Assert.IsTrue(page.HasNextPage);
            Assert.IsFalse(page.HasPreviousPage);
        }

        [TestMethod]
        public void Create_LastPartialPage_ContainsRemainingItems()
        {
            var source = Enumerable.Range(1, 5).AsQueryable();

            var page = PaginatedList<int>.Create(source, 2, 3);

            Assert.AreEqual(2, page.Count);
            Assert.AreEqual(4, page[0]);
            Assert.AreEqual(5, page[1]);
            Assert.IsFalse(page.HasNextPage);
            Assert.IsTrue(page.HasPreviousPage);
        }

        [TestMethod]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            var source = Enumerable.Empty<int>().AsQueryable();

            var page = PaginatedList<int>.Create(source, 1, 10);

            Assert.AreEqual(0, page.Count);
            Assert.AreEqual(0, page.TotalPages);
            Assert.IsFalse(page.HasPreviousPage);
            Assert.IsFalse(page.HasNextPage);
        }

        [TestMethod]
        public void TotalPages_ExactDivision_CalculatesCorrectly()
        {
            // 20 items / 10 per page = exactly 2 pages
            var list = new PaginatedList<int>(new List<int>(), 20, 1, 10);
            Assert.AreEqual(2, list.TotalPages);
        }
    }
}

using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;

namespace ContosoUniversity.Tests.Services
{
    [TestClass]
    public sealed class NotificationServiceTests
    {
        private NotificationService _sut;

        [TestInitialize]
        public void Setup()
        {
            NotificationQueueHelper.DrainQueue();
            _sut = new NotificationService();
        }

        [TestCleanup]
        public void Cleanup()
        {
            NotificationQueueHelper.DrainQueue();
            _sut.Dispose();
        }

        [TestMethod]
        public void SendNotification_Create_EnqueuesWithCorrectMessage()
        {
            _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);

            var notification = _sut.ReceiveNotification();

            Assert.IsNotNull(notification);
            Assert.AreEqual("Student", notification.EntityType);
            Assert.AreEqual("1", notification.EntityId);
            Assert.AreEqual("CREATE", notification.Operation);
            Assert.AreEqual("New Student 'John Doe' has been created", notification.Message);
            Assert.IsFalse(notification.IsRead);
        }

        [TestMethod]
        public void SendNotification_Update_GeneratesUpdateMessage()
        {
            _sut.SendNotification("Course", "101", "Math 101", EntityOperation.UPDATE);

            var notification = _sut.ReceiveNotification();
            Assert.AreEqual("Course 'Math 101' has been updated", notification.Message);
        }

        [TestMethod]
        public void SendNotification_Delete_GeneratesDeleteMessage()
        {
            _sut.SendNotification("Department", "5", "Engineering", EntityOperation.DELETE);

            var notification = _sut.ReceiveNotification();
            Assert.AreEqual("Department 'Engineering' has been deleted", notification.Message);
        }

        [TestMethod]
        public void SendNotification_NoDisplayName_UsesEntityId()
        {
            _sut.SendNotification("Student", "42", EntityOperation.CREATE);

            var notification = _sut.ReceiveNotification();
            Assert.AreEqual("New Student (ID: 42) has been created", notification.Message);
        }

        [TestMethod]
        public void SendNotification_NullDisplayName_UsesEntityId()
        {
            _sut.SendNotification("Student", "42", null, EntityOperation.CREATE);

            var notification = _sut.ReceiveNotification();
            Assert.AreEqual("New Student (ID: 42) has been created", notification.Message);
        }

        [TestMethod]
        public void SendNotification_EmptyDisplayName_UsesEntityId()
        {
            _sut.SendNotification("Student", "42", "", EntityOperation.CREATE);

            var notification = _sut.ReceiveNotification();
            Assert.AreEqual("New Student (ID: 42) has been created", notification.Message);
        }

        [TestMethod]
        public void SendNotification_NullUserName_DefaultsToSystem()
        {
            _sut.SendNotification("Student", "1", "Test", EntityOperation.CREATE);

            var notification = _sut.ReceiveNotification();
            Assert.AreEqual("System", notification.CreatedBy);
        }

        [TestMethod]
        public void SendNotification_WithUserName_SetsCreatedBy()
        {
            _sut.SendNotification("Student", "1", "Test", EntityOperation.CREATE, "admin");

            var notification = _sut.ReceiveNotification();
            Assert.AreEqual("admin", notification.CreatedBy);
        }

        [TestMethod]
        public void ReceiveNotification_EmptyQueue_ReturnsNull()
        {
            var result = _sut.ReceiveNotification();
            Assert.IsNull(result);
        }

        [TestMethod]
        public void ReceiveNotification_MultipleMessages_ReturnsFIFO()
        {
            _sut.SendNotification("A", "1", "First", EntityOperation.CREATE);
            _sut.SendNotification("B", "2", "Second", EntityOperation.UPDATE);

            var first = _sut.ReceiveNotification();
            var second = _sut.ReceiveNotification();

            Assert.AreEqual("A", first.EntityType);
            Assert.AreEqual("B", second.EntityType);
        }

        [TestMethod]
        public void MarkAsRead_DoesNotThrow()
        {
            // MarkAsRead is a no-op, just verify it doesn't throw
            _sut.MarkAsRead(999);
        }

        [TestMethod]
        public void Dispose_DoesNotThrow()
        {
            _sut.Dispose();
            // Can still call methods on a new instance after dispose (static queue)
            var svc2 = new NotificationService();
            svc2.SendNotification("Test", "1", EntityOperation.CREATE);
            Assert.IsNotNull(svc2.ReceiveNotification());
        }

        [TestMethod]
        public void SendNotification_QueueOverflow_TrimmsOldEntries()
        {
            // Enqueue more than 500 notifications
            for (int i = 0; i < 510; i++)
            {
                _sut.SendNotification("Entity", i.ToString(), $"Item {i}", EntityOperation.CREATE);
            }

            // Queue should be capped at ~500
            int count = 0;
            while (_sut.ReceiveNotification() != null) count++;
            Assert.IsTrue(count <= 500, $"Queue should be capped but had {count} items");
        }
    }
}

