using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using System;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class HomeControllerTests
    {
        private SchoolContext _context;
        private HomeController _sut;

        [TestInitialize]
        public void Setup()
        {
            NotificationQueueHelper.DrainQueue();
            _context = TestDbContextFactory.Create();
            _sut = new HomeController(_context);
        }

        [TestCleanup]
        public void Cleanup()
        {
            NotificationQueueHelper.DrainQueue();
            _sut?.Dispose();
        }

        [TestMethod]
        public void Index_ReturnsViewResult()
        {
            var result = _sut.Index();
            Assert.IsInstanceOfType<ViewResult>(result);
        }

        [TestMethod]
        public void About_NoStudents_ReturnsEmptyList()
        {
            var result = _sut.About() as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as List<EnrollmentDateGroup>;
            Assert.IsNotNull(model);
            Assert.AreEqual(0, model.Count);
        }

        [TestMethod]
        public void About_WithStudents_GroupsByEnrollmentDate()
        {
            var date1 = new DateTime(2023, 9, 1);
            var date2 = new DateTime(2024, 1, 15);
            _context.Students.AddRange(
                new Student { LastName = "A", FirstMidName = "A", EnrollmentDate = date1 },
                new Student { LastName = "B", FirstMidName = "B", EnrollmentDate = date1 },
                new Student { LastName = "C", FirstMidName = "C", EnrollmentDate = date2 }
            );
            _context.SaveChanges();

            var result = _sut.About() as ViewResult;
            var model = result.Model as List<EnrollmentDateGroup>;

            Assert.AreEqual(2, model.Count);
            var group1 = model.Single(g => g.EnrollmentDate == date1);
            var group2 = model.Single(g => g.EnrollmentDate == date2);
            Assert.AreEqual(2, group1.StudentCount);
            Assert.AreEqual(1, group2.StudentCount);
        }

        [TestMethod]
        public void Contact_SetsViewBagMessage()
        {
            var result = _sut.Contact() as ViewResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Your contact page.", result.ViewData["Message"]);
        }

        [TestMethod]
        public void Error_ReturnsViewResult()
        {
            var result = _sut.Error();
            Assert.IsInstanceOfType<ViewResult>(result);
        }

        [TestMethod]
        public void Unauthorized_SetsMessage_ReturnsView()
        {
            var result = _sut.Unauthorized() as ViewResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("You don't have permission to access this resource.", result.ViewData["Message"]);
        }
    }
}

using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using System;
using System.Collections.Generic;
using System.Linq;
using Newtonsoft.Json;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class NotificationsControllerTests
    {
        private SchoolContext _context;
        private NotificationsController _sut;

        [TestInitialize]
        public void Setup()
        {
            NotificationQueueHelper.DrainQueue();
            _context = TestDbContextFactory.Create();
            _sut = new NotificationsController(_context);
        }

        [TestCleanup]
        public void Cleanup()
        {
            NotificationQueueHelper.DrainQueue();
            _sut?.Dispose();
        }

        [TestMethod]
        public void GetNotifications_EmptyQueue_ReturnsSuccessWithZeroCount()
        {
            var result = _sut.GetNotifications();

            Assert.IsNotNull(result);
            dynamic value = result.Value;
            Assert.IsNotNull(value);
            var dict = ToDictionary(value);
            Assert.AreEqual(true, dict["success"]);
            Assert.AreEqual(0, ((System.Collections.IList)dict["notifications"]).Count);
            Assert.AreEqual(0, dict["count"]);
        }

        [TestMethod]
        public void GetNotifications_WithNotifications_ReturnsUpTo10()
        {
            var svc = new NotificationService();
            for (int i = 0; i < 15; i++)
            {
                svc.SendNotification("Entity", i.ToString(), $"Item {i}", EntityOperation.CREATE);
            }

            var result = _sut.GetNotifications();
            var dict = ToDictionary(result.Value);

            Assert.AreEqual(true, dict["success"]);
            Assert.AreEqual(10, dict["count"]);
        }

        [TestMethod]
        public void GetNotifications_WithFewNotifications_ReturnsAll()
        {
            var svc = new NotificationService();
            svc.SendNotification("Student", "1", "Alice", EntityOperation.CREATE);
            svc.SendNotification("Course", "101", "Math", EntityOperation.UPDATE);

            var result = _sut.GetNotifications();
            var dict = ToDictionary(result.Value);

            Assert.AreEqual(true, dict["success"]);
            Assert.AreEqual(2, dict["count"]);
        }

        [TestMethod]
        public void MarkAsRead_ReturnsSuccess()
        {
            var result = _sut.MarkAsRead(1);
            var dict = ToDictionary(result.Value);

            Assert.AreEqual(true, dict["success"]);
        }

        [TestMethod]
        public void Index_ReturnsViewResult()
        {
            var result = _sut.Index();
            Assert.IsInstanceOfType<ViewResult>(result);
        }

        private static Dictionary<string, object> ToDictionary(object anonymousObj)
        {
            return anonymousObj.GetType().GetProperties()
                .ToDictionary(p => p.Name, p => p.GetValue(anonymousObj));
        }
    }
}

using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using System;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class DepartmentsControllerTests
    {
        private SchoolContext _context;
        private DepartmentsController _sut;

        [TestInitialize]
        public void Setup()
        {
            NotificationQueueHelper.DrainQueue();
            _context = TestDbContextFactory.Create();
            _sut = new DepartmentsController(_context);
        }

        [TestCleanup]
        public void Cleanup()
        {
            NotificationQueueHelper.DrainQueue();
            _sut?.Dispose();
        }

        private Department CreateDepartment(string name = "Engineering", decimal budget = 100000m)
        {
            var dept = new Department
            {
                Name = name,
                Budget = budget,
                StartDate = new DateTime(2020, 9, 1)
            };
            _context.Departments.Add(dept);
            _context.SaveChanges();
            return dept;
        }

        [TestMethod]
        public void Index_ReturnsDepartmentsList()
        {
            CreateDepartment("CS");
            CreateDepartment("Math");

            var result = _sut.Index() as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as List<Department>;
            Assert.AreEqual(2, model.Count);
        }

        [TestMethod]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _sut.Details(null);
            Assert.IsInstanceOfType<StatusCodeResult>(result);
            Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
        }

        [TestMethod]
        public void Details_NotFound_ReturnsNotFound()
        {
            var result = _sut.Details(999);
            Assert.IsInstanceOfType<NotFoundResult>(result);
        }

        [TestMethod]
        public void Details_ValidId_ReturnsViewWithDepartment()
        {
            var dept = CreateDepartment();

            var result = _sut.Details(dept.DepartmentID) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Department;
            Assert.AreEqual("Engineering", model.Name);
        }

        [TestMethod]
        public void Create_GET_SetsInstructorSelectList()
        {
            var result = _sut.Create() as ViewResult;

            Assert.IsNotNull(result);
            Assert.IsNotNull(result.ViewData["InstructorID"]);
        }

        [TestMethod]
        public void Create_POST_ValidDepartment_RedirectsToIndex()
        {
            var dept = new Department
            {
                Name = "Physics",
                Budget = 50000m,
                StartDate = new DateTime(2023, 1, 1)
            };

            var result = _sut.Create(dept) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.AreEqual(1, _context.Departments.Count());
        }

        [TestMethod]
        public void Create_POST_InvalidModelState_ReturnsView()
        {
            _sut.ModelState.AddModelError("Name", "Required");
            var dept = new Department();

            var result = _sut.Create(dept) as ViewResult;

            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void Edit_GET_NullId_ReturnsBadRequest()
        {
            var result = _sut.Edit((int?)null);
            Assert.IsInstanceOfType<StatusCodeResult>(result);
            Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
        }

        [TestMethod]
        public void Edit_GET_NotFound_ReturnsNotFound()
        {
            var result = _sut.Edit(999);
            Assert.IsInstanceOfType<NotFoundResult>(result);
        }

        [TestMethod]
        public void Edit_GET_ValidId_ReturnsViewWithDepartment()
        {
            var dept = CreateDepartment();

            var result = _sut.Edit(dept.DepartmentID) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Department;
            Assert.AreEqual("Engineering", model.Name);
        }

        [TestMethod]
        public void Edit_POST_ValidDepartment_RedirectsToIndex()
        {
            var dept = CreateDepartment();
            // Detach so we can re-attach with Modified state
            _context.Entry(dept).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            dept.Name = "Updated Engineering";

            var result = _sut.Edit(dept) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
        }

        [TestMethod]
        public void Edit_POST_InvalidModelState_ReturnsView()
        {
            _sut.ModelState.AddModelError("Name", "Required");
            var dept = new Department { DepartmentID = 1 };

            var result = _sut.Edit(dept) as ViewResult;

            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void Delete_GET_NullId_ReturnsBadRequest()
        {
            var result = _sut.Delete(null);
            Assert.IsInstanceOfType<StatusCodeResult>(result);
            Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
        }

        [TestMethod]
        public void Delete_GET_NotFound_ReturnsNotFound()
        {
            var result = _sut.Delete(999);
            Assert.IsInstanceOfType<NotFoundResult>(result);
        }

        [TestMethod]
        public void Delete_GET_ValidId_ReturnsViewWithDepartment()
        {
            var dept = CreateDepartment();

            var result = _sut.Delete(dept.DepartmentID) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Department;
            Assert.AreEqual("Engineering", model.Name);
        }

        [TestMethod]
        public void DeleteConfirmed_RemovesDepartment_RedirectsToIndex()
        {
            var dept = CreateDepartment();

            var result = _sut.DeleteConfirmed(dept.DepartmentID) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.AreEqual(0, _context.Departments.Count());
        }

        [TestMethod]
        public void Create_POST_SendsNotification()
        {
            var dept = new Department
            {
                Name = "Biology",
                Budget = 30000m,
                StartDate = new DateTime(2023, 6, 1)
            };

            _sut.Create(dept);

            var svc = new ContosoUniversity.Services.NotificationService();
            var notification = svc.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("Department", notification.EntityType);
            Assert.AreEqual("CREATE", notification.Operation);
        }

        [TestMethod]
        public void DeleteConfirmed_SendsNotification()
        {
            var dept = CreateDepartment("Chemistry");
            NotificationQueueHelper.DrainQueue();

            _sut.DeleteConfirmed(dept.DepartmentID);

            var svc = new ContosoUniversity.Services.NotificationService();
            var notification = svc.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("DELETE", notification.Operation);
        }
    }
}

using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Microsoft.AspNetCore.Http;
using System;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class StudentsControllerTests
    {
        private SchoolContext _context;
        private StudentsController _sut;

        [TestInitialize]
        public void Setup()
        {
            NotificationQueueHelper.DrainQueue();
            _context = TestDbContextFactory.Create();
            _sut = new StudentsController(_context);

            // Setup TempData for controllers that use it
            _sut.TempData = new TempDataDictionary(
                new DefaultHttpContext(),
                new SessionStateTempDataProvider(new SessionStateTempDataSerializer()));
        }

        [TestCleanup]
        public void Cleanup()
        {
            NotificationQueueHelper.DrainQueue();
            _sut?.Dispose();
        }

        private Student AddStudent(string lastName = "Smith", string firstName = "John", DateTime? enrollmentDate = null)
        {
            var student = new Student
            {
                LastName = lastName,
                FirstMidName = firstName,
                EnrollmentDate = enrollmentDate ?? new DateTime(2023, 9, 1)
            };
            _context.Students.Add(student);
            _context.SaveChanges();
            return student;
        }

        // -- Index tests --

        [TestMethod]
        public void Index_NoStudents_ReturnsEmptyPaginatedList()
        {
            var result = _sut.Index(null, null, null, null) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(0, model.Count);
        }

        [TestMethod]
        public void Index_WithStudents_ReturnsFirstPage()
        {
            for (int i = 0; i < 15; i++)
                AddStudent($"Student{i:D2}", "Test");

            var result = _sut.Index(null, null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.AreEqual(10, model.Count); // page size = 10
            Assert.AreEqual(1, model.PageIndex);
            Assert.IsTrue(model.HasNextPage);
            Assert.IsFalse(model.HasPreviousPage);
        }

        [TestMethod]
        public void Index_SecondPage_ReturnsFiveStudents()
        {
            for (int i = 0; i < 15; i++)
                AddStudent($"Student{i:D2}", "Test");

            var result = _sut.Index(null, null, null, 2) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.AreEqual(5, model.Count);
            Assert.AreEqual(2, model.PageIndex);
            Assert.IsFalse(model.HasNextPage);
            Assert.IsTrue(model.HasPreviousPage);
        }

        [TestMethod]
        public void Index_DefaultSort_OrdersByLastNameAsc()
        {
            AddStudent("Zulu", "A");
            AddStudent("Alpha", "B");

            var result = _sut.Index(null, null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.AreEqual("Alpha", model[0].LastName);
            Assert.AreEqual("Zulu", model[1].LastName);
        }

        [TestMethod]
        public void Index_NameDescSort_OrdersByLastNameDesc()
        {
            AddStudent("Alpha", "A");
            AddStudent("Zulu", "B");

            var result = _sut.Index("name_desc", null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.AreEqual("Zulu", model[0].LastName);
            Assert.AreEqual("Alpha", model[1].LastName);
        }

        [TestMethod]
        public void Index_DateSort_OrdersByEnrollmentDateAsc()
        {
            AddStudent("A", "A", new DateTime(2024, 1, 1));
            AddStudent("B", "B", new DateTime(2023, 1, 1));

            var result = _sut.Index("Date", null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.AreEqual(new DateTime(2023, 1, 1), model[0].EnrollmentDate);
        }

        [TestMethod]
        public void Index_DateDescSort_OrdersByEnrollmentDateDesc()
        {
            AddStudent("A", "A", new DateTime(2023, 1, 1));
            AddStudent("B", "B", new DateTime(2024, 1, 1));

            var result = _sut.Index("date_desc", null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.AreEqual(new DateTime(2024, 1, 1), model[0].EnrollmentDate);
        }

        [TestMethod]
        public void Index_SearchString_FiltersStudentsByLastName()
        {
            AddStudent("Smith", "John");
            AddStudent("Jones", "Jane");

            var result = _sut.Index(null, null, "Smith", null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.AreEqual(1, model.Count);
            Assert.AreEqual("Smith", model[0].LastName);
        }

        [TestMethod]
        public void Index_SearchString_FiltersStudentsByFirstName()
        {
            AddStudent("Smith", "John");
            AddStudent("Jones", "Jane");

            var result = _sut.Index(null, null, "Jane", null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.AreEqual(1, model.Count);
            Assert.AreEqual("Jane", model[0].FirstMidName);
        }

        [TestMethod]
        public void Index_NewSearchString_ResetsToPage1()
        {
            for (int i = 0; i < 15; i++)
                AddStudent($"Name{i}", "Test");

            var result = _sut.Index(null, null, "Name1", null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.AreEqual(1, model.PageIndex);
        }

        [TestMethod]
        public void Index_SetsViewBagSortParameters()
        {
            var result = _sut.Index(null, null, null, null) as ViewResult;

            Assert.AreEqual("name_desc", result.ViewData["NameSortParm"]);
            Assert.AreEqual("Date", result.ViewData["DateSortParm"]);
        }

        [TestMethod]
        public void Index_SortByDate_ViewBagDateSortParmIsDateDesc()
        {
            var result = _sut.Index("Date", null, null, null) as ViewResult;

            Assert.AreEqual("date_desc", result.ViewData["DateSortParm"]);
        }

        // -- Details tests --

        [TestMethod]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _sut.Details(null);
            Assert.IsInstanceOfType<StatusCodeResult>(result);
            Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
        }

        [TestMethod]
        public void Details_ValidId_ReturnsViewWithStudent()
        {
            var student = AddStudent();

            var result = _sut.Details(student.ID) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Student;
            Assert.AreEqual("Smith", model.LastName);
        }

        // -- Create tests --

        [TestMethod]
        public void Create_GET_ReturnsViewWithDefaultDate()
        {
            var result = _sut.Create() as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Student;
            Assert.IsNotNull(model);
            Assert.AreEqual(DateTime.Today, model.EnrollmentDate.Date);
        }

        [TestMethod]
        public void Create_POST_ValidStudent_RedirectsToIndex()
        {
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "Student",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            var result = _sut.Create(student) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.AreEqual(1, _context.Students.Count());
        }

        [TestMethod]
        public void Create_POST_MinValueDate_AddsModelError()
        {
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "Student",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _sut.Create(student) as ViewResult;

            Assert.IsNotNull(result);
            Assert.IsTrue(_sut.ModelState.ContainsKey("EnrollmentDate"));
        }

        [TestMethod]
        public void Create_POST_DateTooEarly_AddsModelError()
        {
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "Student",
                EnrollmentDate = new DateTime(1752, 1, 1)
            };

