            {
                Name = name,
                Budget = 100000,
                StartDate = new DateTime(2020, 1, 1),
                InstructorID = instructorId
            };
            _context.Departments.Add(dept);
            _context.SaveChanges();
            return dept;
        }

        private Course AddCourse(int courseId, string title = "Test Course")
        {
            var dept = _context.Departments.FirstOrDefault() ?? AddDepartment();
            var course = new Course
            {
                CourseID = courseId,
                Title = title,
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };
