        }

        [TestMethod]
        public void Delete_GET_NotFound_ReturnsNotFound()
        {
            var result = _sut.Delete(999);
            Assert.IsInstanceOfType<NotFoundResult>(result);
        }

        [TestMethod]
        public void Delete_GET_ValidId_ReturnsView()
        {
            var instructor = AddInstructor();

            var result = _sut.Delete(instructor.ID) as ViewResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Smith", (result.Model as Instructor).LastName);
        }

        [TestMethod]
        public void DeleteConfirmed_RemovesInstructor_RedirectsToIndex()
        {
            var instructor = AddInstructor();

            var result = _sut.DeleteConfirmed(instructor.ID) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.AreEqual(0, _context.Instructors.Count());
        }

        [TestMethod]
        public void DeleteConfirmed_NullsDepartmentAdministrator()
        {
            var instructor = AddInstructor();
            var dept = AddDepartment("Test Dept", instructor.ID);

            _sut.DeleteConfirmed(instructor.ID);

            var updatedDept = _context.Departments.Find(dept.DepartmentID);
            Assert.IsNull(updatedDept.InstructorID);
        }

        [TestMethod]
